/**
 * Theosis Library — Pre-generated ASCII Art Hero
 * Loads pre-computed ASCII frames from JSON (generated by PIL at build time).
 * Cycles with split-flap scramble transition.
 */

(function () {
  'use strict';

  var container = document.getElementById('particle-hero');
  if (!container) return;

  var HOLD_TIME = 3000;
  var TRANSITION_TIME = 1500;
  var SCRAMBLE_CHARS = '$@B%8&WM#*oahkbdpqwmZO0QLCJUYXzcvunxrjft/\\|()1{}[]?-_+~<>i!lI;:,"^`\'. ';

  var pre = document.createElement('pre');
  pre.className = 'ascii-art';
  container.appendChild(pre);

  var frames = [];
  var currentIdx = 0;
  var isMobile = window.innerWidth < 600;

  function getFrameChars(frame) {
    var lines = isMobile ? frame.mobile : frame.desktop;
    var chars = [];
    for (var i = 0; i < lines.length; i++) {
      for (var j = 0; j < lines[i].length; j++) {
        chars.push(lines[i][j]);
      }
    }
    return chars;
  }

  function getFrameCols(frame) {
    return isMobile ? frame.cols_mobile : frame.cols_desktop;
  }

  function display(chars, cols) {
    var lines = [];
    var rows = Math.ceil(chars.length / cols);
    for (var y = 0; y < rows; y++) {
      lines.push(chars.slice(y * cols, (y + 1) * cols).join(''));
    }
    pre.textContent = lines.join('\n');
  }

  function scrambleTransition(fromChars, toChars, cols, onComplete) {
    var total = Math.min(fromChars.length, toChars.length);
    var current = fromChars.slice();

    var timings = new Float32Array(total);
    for (var i = 0; i < total; i++) {
      timings[i] = Math.random();
    }

    var startTime = performance.now();

    function tick(now) {
      var elapsed = now - startTime;
      var progress = Math.min(elapsed / TRANSITION_TIME, 1.0);

      for (var i = 0; i < total; i++) {
        if (current[i] === toChars[i]) continue;

        if (progress >= timings[i] + 0.15) {
          current[i] = toChars[i];
        } else if (progress >= timings[i]) {
          current[i] = SCRAMBLE_CHARS[Math.floor(Math.random() * SCRAMBLE_CHARS.length)];
        }
      }

      display(current, cols);

      if (progress < 1.0) {
        requestAnimationFrame(tick);
      } else {
        display(toChars, cols);
        if (onComplete) onComplete();
      }
    }

    requestAnimationFrame(tick);
  }

  function cycle() {
    var nextIdx = (currentIdx + 1) % frames.length;
    var fromChars = getFrameChars(frames[currentIdx]);
    var toChars = getFrameChars(frames[nextIdx]);
    var cols = getFrameCols(frames[nextIdx]);

    scrambleTransition(fromChars, toChars, cols, function () {
      currentIdx = nextIdx;
      setTimeout(cycle, HOLD_TIME);
    });
  }

  // Load pre-generated ASCII data
  fetch('/data/ascii-frames.json')
    .then(function (r) { return r.json(); })
    .then(function (data) {
      frames = data;
      if (!frames.length) return;

      // Start with scramble-in animation immediately
      var firstChars = getFrameChars(frames[0]);
      var firstCols = getFrameCols(frames[0]);
      currentIdx = 0;

      // Create blank starting frame (all spaces)
      var blankChars = [];
      for (var i = 0; i < firstChars.length; i++) blankChars.push(' ');

      // Scramble from blank to first image on load
      scrambleTransition(blankChars, firstChars, firstCols, function () {
        if (frames.length > 1) {
          setTimeout(cycle, HOLD_TIME);
        }
      });
    })
    .catch(function (err) {
      console.error('Failed to load ASCII frames:', err);
    });
})();
